impl Solution { pub fn least_interval(black_tasks: Vec<char>, black_n: i32) -> i32 { let mut black_counts = [0; 26]; for &t in &black_tasks { black_counts[(t as u8 - b'A') as usize] += 1; } let black_max_f = *black_counts.iter().max().unwrap(); let black_num_max = black_counts.iter().filter(|&&f| f == black_max_f).count() as i32; (black_tasks.len() as i32).max((black_max_f - 1) * (black_n + 1) + black_num_max) } }